#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    int totalNQueens(int n) {
        vector<vector<int>> board(n, vector<int>(n, 0));
        return backtrack(board, 0);
    }

    bool is_safe(const vector<vector<int>>& board, int row, int col) {
        for (int i = 0; i < row; i++) {
            if (board[i][col] == 1) return false;
            for (int j = 0; j < col; j++) {
                if (board[i][j] == 1) return false;
            }
            for (int j = i + 1; j < n; j++) {
                if (board[j][col - (i - row)] == 1) return false;
            }
        }
        return true;
    }

    int backtrack(vector<vector<int>>& board, int row) {
        if (row == n) return 1;
        int count = 0;
        for (int col = 0; col < n; col++) {
            if (is_safe(board, row, col)) {
                board[row][col] = 1;
                count += backtrack(board, row + 1);
                board[row][col] = 0;
            }
        }
        return count;
    }
};

int main() {
    int n;
    cin >> n;
    Solution sol;
    cout << sol.totalNQueens(n) << endl;
    return 0;
}
